import pytest
from solution import is_balanced_parens


# ---------------------------------------------------------------------------
# Happy path – balanced inputs
# ---------------------------------------------------------------------------

class TestBalancedInputs:
    def test_empty_string(self):
        assert is_balanced_parens("") is True

    def test_single_pair_parens(self):
        assert is_balanced_parens("()") is True

    def test_single_pair_brackets(self):
        assert is_balanced_parens("[]") is True

    def test_single_pair_braces(self):
        assert is_balanced_parens("{}") is True

    def test_sequential_pairs(self):
        assert is_balanced_parens("()[]{}") is True

    def test_nested_same_type(self):
        assert is_balanced_parens("((()))") is True

    def test_nested_mixed_types(self):
        assert is_balanced_parens("{[()]}") is True

    def test_complex_nested(self):
        assert is_balanced_parens("{[()()]}[]()") is True

    def test_deeply_nested(self):
        assert is_balanced_parens("((((((()))))))") is True

    def test_string_with_non_bracket_characters(self):
        """Non-bracket characters should be ignored."""
        assert is_balanced_parens("a(b)c") is True

    def test_alphanumeric_only(self):
        """No brackets at all – trivially balanced."""
        assert is_balanced_parens("abc123") is True

    def test_brackets_interspersed_with_text(self):
        assert is_balanced_parens("foo(bar[baz]{qux})") is True


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------

class TestEdgeCases:
    def test_single_open_paren(self):
        assert is_balanced_parens("(") is False

    def test_single_close_paren(self):
        assert is_balanced_parens(")") is False

    def test_single_open_bracket(self):
        assert is_balanced_parens("[") is False

    def test_single_close_bracket(self):
        assert is_balanced_parens("]") is False

    def test_single_open_brace(self):
        assert is_balanced_parens("{") is False

    def test_single_close_brace(self):
        assert is_balanced_parens("}") is False

    def test_reversed_pair_parens(self):
        assert is_balanced_parens(")(") is False

    def test_reversed_pair_brackets(self):
        assert is_balanced_parens("][") is False

    def test_reversed_pair_braces(self):
        assert is_balanced_parens("}{") is False

    def test_mismatched_open_close(self):
        assert is_balanced_parens("(]") is False

    def test_mismatched_open_close_2(self):
        assert is_balanced_parens("[)") is False

    def test_mismatched_open_close_3(self):
        assert is_balanced_parens("{)") is False

    def test_extra_closing_bracket(self):
        assert is_balanced_parens("())") is False

    def test_extra_opening_bracket(self):
        assert is_balanced_parens("(()") is False

    def test_interleaved_not_nested(self):
        """Interleaved brackets are not properly nested."""
        assert is_balanced_parens("([)]") is False

    def test_interleaved_braces_brackets(self):
        assert is_balanced_parens("{[}]") is False

    def test_only_whitespace(self):
        """Whitespace contains no brackets – should be balanced."""
        assert is_balanced_parens("   ") is True

    def test_newlines_and_tabs(self):
        assert is_balanced_parens("\n\t") is True
